// MongoDB CRUD operations

// INSERT
db.employees.insertOne({
    name: "Alice Smith",
    email: "alice@company.com",
    salary: 95000,
    skills: ["JavaScript", "Python", "SQL"],  // array
    address: {                                  // embedded document
        street: "123 Main St",
        city: "Bangalore",
        pincode: "560001"
    },
    hireDate: new Date("2022-03-15")
});

// Multiple documents
db.employees.insertMany([
    { name: "Bob",   salary: 78000, dept: "Engineering" },
    { name: "Carol", salary: 85000, dept: "Marketing"   }
]);

// FIND / READ
db.employees.find({ salary: { $gt: 80000 } });           // salary > 80000
db.employees.find({ dept: "Engineering", salary: { $gte: 90000 } }); // AND
db.employees.find({ $or: [{ dept: "Engineering" }, { salary: { $gt: 90000 } }] });
db.employees.find({ skills: "Python" });                  // array contains
db.employees.find({}, { name: 1, salary: 1, _id: 0 });   // projection
db.employees.find().sort({ salary: -1 }).limit(5);        // top 5 earners

// UPDATE
db.employees.updateOne(
    { name: "Alice Smith" },              // filter
    { $set: { salary: 105000 },           // update operators
      $push: { skills: "MongoDB" } }      // add to array
);
db.employees.updateMany(
    { dept: "Engineering" },
    { $inc: { salary: 5000 } }            // increment all Engineering salaries
);

// DELETE
db.employees.deleteOne({ name: "Bob" });
db.employees.deleteMany({ salary: { $lt: 50000 } });

// Reference design (like Foreign Key)
// Department collection
db.departments.insertOne({ _id: ObjectId("..."), name: "Engineering" });
// Employee references department
db.employees.insertOne({ name: "Dave", dept_id: ObjectId("...") }); // reference
